// Grab all the items from the previous node
const allWorkflows = $input.all().map(item => {
    // If the node is connected AFTER Airtable, the data is hidden inside "fields"
    if (item.json.fields) {
        return item.json.fields;
    }
    // If it's connected before Airtable, the data is right at the top
    return item.json;
});

// 1. Generate Date Internally (Bulletproof: no longer relies on upstream data)
const today = new Date();
const formattedDate = today.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });

// 2. Safety Net: Check if the array is actually empty
if (allWorkflows.length === 0 || !allWorkflows[0].workflowName) {
    return [{
        json: {
            text: `📊 *n8n Daily Digest – ${formattedDate}*\n\nTotal runs: 0   |   Success rate: 100.0%   |   Errors: 0\n\n💤 *Quiet day. No automated workflows were triggered in the last 24 hours.*\n\n🔗 View full dashboard → <https://airtable.com/YOUR_BASE_ID|Airtable link>`
        }
    }];
}

// 3. Calculate Global Metrics (Total runs, total errors, overall success)
let globalRuns = 0;
let globalErrors = 0;

allWorkflows.forEach(wf => {
    // We use fallback || 0 just in case the numbers are missing
    globalRuns += (wf.totalRuns || 0);
    globalErrors += (wf.errorCount || 0);
});

let globalSuccessRate = "100.0";
if (globalRuns > 0) {
    globalSuccessRate = (((globalRuns - globalErrors) / globalRuns) * 100).toFixed(1);
}

// 4. Build "Most Active" Section
const topActive = allWorkflows.slice(0, 3);
let activeText = "";
topActive.forEach((wf, index) => {
    activeText += `${index + 1}. ${wf.workflowName} — ${wf.totalRuns} runs\n`;
});

// 5. Build "Most Errors" Section
const topErrors = allWorkflows
    .filter(wf => wf.errorCount > 0)
    .sort((a, b) => b.errorCount - a.errorCount)
    .slice(0, 3);

let errorText = "🚨 Most errors\n";
if (topErrors.length > 0) {
    topErrors.forEach((wf, index) => {
        errorText += `${index + 1}. ${wf.workflowName} — ${wf.errorCount} errors (${(wf.successRate * 100).toFixed(1)}% success)\n`;
    });
} else {
    errorText += "None! Great job today.\n";
}

// 6. Construct the final Slack Message text
const slackMessage = `📊 *n8n Daily Digest – ${formattedDate}*\n\n` +
    `Total runs: ${globalRuns}   |   Success rate: ${globalSuccessRate}%   |   Errors: ${globalErrors}\n\n` +
    `🔥 *Most active*\n${activeText}\n` +
    `${errorText}\n` +
    `🔗 View full dashboard → <https://airtable.com/apptuAm73VyH7pcHA/shrRGRx6Nbj2jg2ms|Airtable link>`;

// Output the fully formatted message
return [{
    json: {
        text: slackMessage
    }
}];

// 1. Pull data from both parallel HTTP branches
// (This safely looks back past the Merge node to get the raw API data)
const executionsData = $('GET /executions').first().json.data;
const workflowsData = $('GET /workflows').first().json.data;

// 2. Build the ID-to-Name map from the Workflows data
const workflowMap = {};
if (workflowsData) {
    workflowsData.forEach(wf => {
        workflowMap[wf.id] = wf.name;
    });
}

// 3. Define the 24-hour cutoff window
const cutoffTime = new Date(new Date().getTime() - (24 * 60 * 60 * 1000));
const todayDate = new Date().toISOString().split('T')[0]; // Format: YYYY-MM-DD for Airtable

// 4. Initialize our aggregation object
const stats = {};

// 5. Loop through the executions and aggregate
if (executionsData) {
    executionsData.forEach(exec => {
        const startedAt = new Date(exec.startedAt);

        // PRODUCTION FILTER: Only process runs in the last 24 hours AND ignore manual tests
        if (startedAt >= cutoffTime && exec.mode !== 'manual') {
            const wid = exec.workflowId;

            // If this is the first time we're seeing this workflow, set up its profile
            if (!stats[wid]) {
                stats[wid] = {
                    workflowId: wid,
                    workflowName: workflowMap[wid] || `Unknown Workflow (${wid})`,
                    totalRuns: 0,
                    successCount: 0,
                    errorCount: 0
                };
            }

            // Increment total runs
            stats[wid].totalRuns += 1;

            // Categorize the status
            if (exec.status === 'success') {
                stats[wid].successCount += 1;
            } else if (exec.status === 'error' || exec.status === 'crashed') {
                stats[wid].errorCount += 1;
            }
        }
    });
}

// 6. Format into the final array of items that n8n expects
const results = Object.values(stats).map(stat => {
    // Calculate success rate safely as a pure decimal (0.000 to 1.000) for Airtable
    let successRate = 0;
    if (stat.totalRuns > 0) {
        successRate = parseFloat((stat.successCount / stat.totalRuns).toFixed(3));
    }

    return {
        json: {
            workflowId: stat.workflowId,
            workflowName: stat.workflowName,
            totalRuns: stat.totalRuns,
            errorCount: stat.errorCount,
            successRate: successRate, // Raw decimal for Airtable
            date: todayDate
        }
    };
});

// 7. Sort by totalRuns (highest to lowest) to establish the activityRank
results.sort((a, b) => b.json.totalRuns - a.json.totalRuns);

// Assign the rank based on the sorted order
results.forEach((item, index) => {
    item.json.activityRank = index + 1;
});

// Output the final shaped data
return results;

